test("cross-language RFC 8785 and typed digest vectors", async () => {
  const document = JSON.parse(await readFile("contracts/fixtures/canonicalization-vectors.json", "utf8")) as { vectors: Vector[] };
  assert.ok(document.vectors.length >= 3);
  for (const vector of document.vectors) {
    assert.equal(canonicalizeJson(vector.input), vector.canonical, vector.name);
    assert.equal(await typedDigest(vector.object_type, vector.schema_version, vector.input), vector.digest, vector.name);
  }
});

test("canonicalizer rejects unsafe values", () => {
  assert.throws(() => canonicalizeJson({ value: Number.POSITIVE_INFINITY } as unknown as JsonValue));
  assert.throws(() => canonicalizeJson({ value: "\ud800" }));
  assert.throws(() => canonicalizeJson('{"duplicate":1,"duplicate":2}'));
  assert.throws(() => canonicalizeJson('{"number":1e999}'));
});

test("shared ECDSA and RSA-PSS detached-signature vectors verify", async () => {
  const fixture = JSON.parse(await readFile("contracts/fixtures/signature-verification-vectors.json", "utf8")) as SignatureFixture;
  assert.equal(await registryDigest(fixture.registry), fixture.registry_hash);
  assert.equal(await validatePublicKeyRegistry(fixture.registry), true);
  const expected = {
    objectType: fixture.expected.object_type,
    objectSchemaID: fixture.expected.object_schema_id,
    objectSchemaVersion: fixture.expected.object_schema_version,
    purpose: fixture.expected.purpose,
    environment: fixture.expected.environment,
    tenantScope: fixture.expected.tenant_scope,
    migrationScope: fixture.expected.migration_scope,
    registryHash: fixture.registry_hash,
    at: new Date(fixture.expected.at),
  };
  const algorithms = new Set<string>();
  for (const vector of fixture.vectors) {
    algorithms.add(vector.envelope.algorithm);
    assert.equal(await verifyDetached(fixture.payload, vector.envelope, fixture.registry, expected), true, vector.name);
  }
  assert.deepEqual([...algorithms].sort(), ["ECDSA_P256_SHA256", "RSA_PSS_SHA256"]);

  const envelope = fixture.vectors.find((vector) => vector.envelope.algorithm === "ECDSA_P256_SHA256")?.envelope;
  assert.ok(envelope, "shared fixture must contain an ECDSA vector");
  assert.deepEqual(
    fixture.negative_ecdsa_der_vectors.map((vector) => vector.name).sort(),
    [
      "appended-byte",
      "extra-sequence-content",
      "indefinite-length",
      "integer-overrun",
      "missing-required-leading-zero",
      "negative-integer",
      "non-minimal-length-leading-zero",
      "non-minimal-long-form-length",
      "unnecessary-leading-zero",
      "zero-integer",
      "zero-length-integer",
    ],
  );
  for (const vector of fixture.negative_ecdsa_der_vectors) {
    assert.equal(
      await verifyDetached(fixture.payload, { ...envelope, signature_base64: vector.signature_base64 }, fixture.registry, expected),
      false,
      vector.name,
    );
  }
  for (const signature_base64 of ["AA-A", "AAAAA", "AB==", "AAAA\n"]) {
    assert.equal(await verifyDetached(fixture.payload, { ...envelope, signature_base64 }, fixture.registry, expected), false, signature_base64);
  }
  assert.equal(await verifyDetached(fixture.payload, { ...envelope, issued_at: "2026-07-18T01:00:00+00:00" }, fixture.registry, expected), false);
});

test("public-key registry rejects invalid genesis and supersession cycles", async () => {
  const fixture = JSON.parse(await readFile("contracts/fixtures/signature-verification-vectors.json", "utf8")) as SignatureFixture;
  assert.equal(await validatePublicKeyRegistry({ ...fixture.registry, previous_registry_hash: fixture.registry_hash }), false);
  assert.equal(await validatePublicKeyRegistry({ ...fixture.registry, registry_version: 2, previous_registry_hash: null }), false);
  assert.equal(await validatePublicKeyRegistry({ ...fixture.registry, issued_at: "2026-07-18T00:00:00+00:00" }), false);
  assert.equal(await validatePublicKeyRegistry({ ...fixture.registry, issued_at: "2026-07-18T00:00:00.1234567890Z" }), false);
  const self = structuredClone(fixture.registry);
  self.keys[0].status = "superseded";
  self.keys[0].supersedes_kid = self.keys[0].kid;
  assert.equal(await validatePublicKeyRegistry(self), false);
  const cycle = structuredClone(fixture.registry);
  const cycleKid = "fixture-ecdsa-cycle";
  cycle.keys[0].status = "superseded";
  cycle.keys[0].supersedes_kid = cycleKid;
  cycle.keys.push({ ...cycle.keys[0], kid: cycleKid, supersedes_kid: cycle.keys[0].kid });
  assert.equal(await validatePublicKeyRegistry(cycle), false);
  const malformedKey = structuredClone(fixture.registry);
  malformedKey.keys[0].public_key_pem = "-----BEGIN PUBLIC KEY-----\nAAAA\n-----END PUBLIC KEY-----\n";
  assert.equal(await validatePublicKeyRegistry(malformedKey), false);
  const mismatchedKey = structuredClone(fixture.registry);
  mismatchedKey.keys[0].algorithm = "RSA_PSS_SHA256";
  assert.equal(await validatePublicKeyRegistry(mismatchedKey), false);
  const revokedWithoutMetadata = structuredClone(fixture.registry);
  revokedWithoutMetadata.keys[0].status = "revoked";
  assert.equal(await validatePublicKeyRegistry(revokedWithoutMetadata), false);
  const activeWithMetadata = structuredClone(fixture.registry);
  activeWithMetadata.keys[0].revoked_at = "2026-07-18T00:30:00Z";
  activeWithMetadata.keys[0].revocation_reason = "compromised";
  assert.equal(await validatePublicKeyRegistry(activeWithMetadata), false);
  const unsupported = structuredClone(fixture.registry) as unknown as { keys: Array<{ algorithm: string; status: string }> };
  unsupported.keys[0].algorithm = "UNSUPPORTED";
  unsupported.keys[0].status = "unknown";
  assert.equal(await validatePublicKeyRegistry(unsupported as unknown as PublicKeyRegistry), false);
});

type MutableJsonObject = { [key: string]: JsonValue };

async function reidentifyForTest(input: JsonValue, mutate: (object: MutableJsonObject) => void): Promise<JsonValue> {
  const object = structuredClone(input) as MutableJsonObject;
  mutate(object);
  const projection = object.logical_payload_projection as MutableJsonObject;
  const objectType = projection.object_type as string;
  const version = projection.object_schema_version as string;
  const idField = projection.id_field as string;
  const excluded = projection.excluded_fields as ReadonlyArray<string>;
  const equivalents = (projection.equivalent_digest_fields ?? []) as ReadonlyArray<string>;
  const projected: MutableJsonObject = Object.create(null) as MutableJsonObject;
  for (const [field, value] of Object.entries(object)) {
    if (!excluded.includes(field)) projected[field] = value;
  }
  const digest = await typedDigest(objectType, version, projected);
  object[idField] = digest;
  object.logical_payload_sha256 = digest;
  for (const field of equivalents) object[field] = digest;
  return object;
}

test("shared catalog fixture enforces typed identity and strict unique ordering", async () => {
  const fixture = JSON.parse(await readFile("contracts/fixtures/client/valid-customer-incapability-catalog.json", "utf8")) as { instance: JsonValue };
  assert.equal(await verifyContentIdentity(fixture.instance), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(fixture.instance), true);
  const tampered = structuredClone(fixture.instance) as unknown as { items: Array<{ safe_explanation: string }> };
  tampered.items[0].safe_explanation = "Semantically changed while holding every digest field fixed.";
  assert.equal(await verifyContentIdentity(tampered as unknown as JsonValue), false);
  const reversed = await reidentifyForTest(fixture.instance, (object) => {
    const items = object.items as unknown as MutableJsonObject[];
    items.reverse();
  });
  assert.equal(await verifyContentIdentity(reversed), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(reversed), false);
  const duplicate = await reidentifyForTest(fixture.instance, (object) => {
    const items = object.items as unknown as MutableJsonObject[];
    items[1].capability_id = items[0].capability_id;
    items[1].incapability_id = items[0].incapability_id;
  });
  assert.equal(await verifyContentIdentity(duplicate), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(duplicate), false);
  const attackerProjection = await reidentifyForTest(fixture.instance, (object) => {
    const projection = object.logical_payload_projection as MutableJsonObject;
    projection.object_type = "attacker_catalog";
    projection.id_field = "attacker_id";
    projection.domain_separator = "jumpship:attacker_catalog:1.0.0\0";
    projection.excluded_fields = ["attacker_id", "logical_payload_sha256", "logical_payload_projection"];
    projection.equivalent_digest_fields = [];
  });
  assert.equal(await verifyContentIdentity(attackerProjection), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(attackerProjection), false);
  const unknownItemField = await reidentifyForTest(fixture.instance, (object) => {
    const items = object.items as unknown as MutableJsonObject[];
    items[0].unexpected_authority = true;
  });
  assert.equal(await verifyContentIdentity(unknownItemField), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(unknownItemField), false);
  const missingItemField = await reidentifyForTest(fixture.instance, (object) => {
    const items = object.items as unknown as MutableJsonObject[];
    delete items[0].reason_code;
  });
  assert.equal(await verifyContentIdentity(missingItemField), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(missingItemField), false);
  const oversized = await reidentifyForTest(fixture.instance, (object) => {
    const items = object.items as unknown as MutableJsonObject[];
    const template = items[items.length - 1];
    for (let index = 0; index < 300; index += 1) {
      const item = structuredClone(template);
      item.capability_id = `MVP-CAP-Z${index.toString().padStart(4, "0")}`;
      item.incapability_id = `cannot-oversize-${index.toString().padStart(4, "0")}`;
      item.safe_explanation = "x".repeat(2048);
      item.safe_remediation = "y".repeat(2048);
      items.push(item);
    }
  });
  assert.ok(new TextEncoder().encode(canonicalizeJson(oversized)).length > 1_048_576);
  assert.equal(await verifyContentIdentity(oversized), true);
  assert.equal(await verifyCustomerIncapabilityCatalog(oversized), false);
});

function base64(bytes: Uint8Array): string {
  let binary = "";
  for (const byte of bytes) binary += String.fromCharCode(byte);
  return btoa(binary);
}

function publicKeyPEM(bytes: Uint8Array): string {
  const encoded = base64(bytes);
  const lines = encoded.match(/.{1,64}/g) ?? [];
  return `-----BEGIN PUBLIC KEY-----\n${lines.join("\n")}\n-----END PUBLIC KEY-----`;
}

test("detached signature denies tamper/replay/supersession and preserves re-sign identity", async () => {
  const payload: JsonValue = { schema_version: "1.0.0", value: "stable" };
  const keys = await crypto.subtle.generateKey({ name: "RSA-PSS", modulusLength: 2048, publicExponent: new Uint8Array([1, 0, 1]), hash: "SHA-256" }, true, ["sign", "verify"]);
  const successorKeys = await crypto.subtle.generateKey({ name: "RSA-PSS", modulusLength: 2048, publicExponent: new Uint8Array([1, 0, 1]), hash: "SHA-256" }, true, ["sign", "verify"]);
  const publicKey = new Uint8Array(await crypto.subtle.exportKey("spki", keys.publicKey));
  const successorPublicKey = new Uint8Array(await crypto.subtle.exportKey("spki", successorKeys.publicKey));
  const tenant = "018f1234-5678-7abc-8def-0123456789ab";
  const registryID = "a".repeat(64);
  const registry: PublicKeyRegistry = {
    schema_version: "1.0.0", registry_id: registryID, registry_version: 1, previous_registry_hash: null,
    root_fingerprint: "c".repeat(64), purpose_policy_hash: "d".repeat(64), issued_at: "2026-07-18T00:00:00Z",
    keys: [{ kid: "release-a", algorithm: "RSA_PSS_SHA256", public_key_pem: publicKeyPEM(publicKey), purposes: ["release_evidence"],
      environments: ["staging"], tenant_scope: tenant, valid_from: "2026-07-18T00:00:00Z", valid_until: "2026-07-19T00:00:00Z",
      status: "active", supersedes_kid: null, revoked_at: null, revocation_reason: null }],
  };
  const registryHash = await registryDigest(registry);
  const claims: SignatureClaims = {
    schema_version: "1.0.0", object_type: "release_unit",
    object_schema_id: "https://jumpship.dev/contracts/release/release-unit.schema.json", object_schema_version: "1.0.0",
    payload_digest: await typedDigest("release_unit", "1.0.0", payload), purpose: "release_evidence", environment: "staging",
    tenant_scope: tenant, migration_scope: null, kid: "release-a", algorithm: "RSA_PSS_SHA256",
    signer_id: "release-workflow", signer_role: "release-evidence", issued_at: "2026-07-18T01:00:00Z", expires_at: null,
    key_registry_id: registryID, key_registry_hash: registryHash,
  };
  const claimsBytes = new TextEncoder().encode(canonicalizeJson(claims as unknown as JsonValue));
  const signature = new Uint8Array(await crypto.subtle.sign({ name: "RSA-PSS", saltLength: 32 }, keys.privateKey, claimsBytes));
  const envelope = { ...claims, envelope_id: await typedDigest("signature_envelope", "1.0.0", claims as unknown as JsonValue), signature_base64: base64(signature) };
  const expected = { objectType: "release_unit", objectSchemaID: claims.object_schema_id, objectSchemaVersion: "1.0.0", purpose: "release_evidence", environment: "staging", tenantScope: tenant, migrationScope: null, registryHash, at: new Date("2026-07-18T01:01:00Z") };
  assert.equal(await verifyDetached(payload, envelope, registry, expected), true);
  assert.equal(await verifyDetached(payload, envelope, { ...registry, root_fingerprint: "e".repeat(64) }, expected), false);
  assert.equal(await verifyDetached(payload, envelope, registry, { ...expected, at: new Date(Number.NaN) }), false);
  assert.equal(await verifyDetached(payload, envelope, { ...registry, issued_at: "2026-02-30T00:00:00Z" }, expected), false);
  assert.equal(await verifyDetached(payload, envelope, { ...registry, keys: [{ ...registry.keys[0], valid_until: "2026-13-01T00:00:00Z" }] }, expected), false);
  assert.equal(await verifyDetached({ schema_version: "1.0.0", value: "tampered" }, envelope, registry, expected), false);
  const signatureTamper = `${envelope.signature_base64[0] === "A" ? "B" : "A"}${envelope.signature_base64.slice(1)}`;
  assert.equal(await verifyDetached(payload, { ...envelope, signature_base64: signatureTamper }, registry, expected), false);
  assert.equal(await verifyDetached(payload, envelope, registry, { ...expected, purpose: "bundle_promotion" }), false);
  assert.equal(await verifyDetached(payload, envelope, registry, { ...expected, objectType: "qualification_record" }), false);
  assert.equal(await verifyDetached(payload, envelope, registry, { ...expected, objectSchemaVersion: "2.0.0" }), false);
  const identityBefore = claims.payload_digest;
  const resigned = new Uint8Array(await crypto.subtle.sign({ name: "RSA-PSS", saltLength: 32 }, keys.privateKey, claimsBytes));
  assert.equal(claims.payload_digest, identityBefore);
  assert.notEqual(base64(resigned), envelope.signature_base64);
  assert.equal(await typedDigest("signature_envelope", "1.0.0", claims as unknown as JsonValue), envelope.envelope_id);
  const successor: PublicKeyRegistry = { ...registry, registry_id: "f".repeat(64), registry_version: 2, previous_registry_hash: registryHash, keys: [
    { ...registry.keys[0], status: "superseded" },
    { ...registry.keys[0], kid: "release-b", public_key_pem: publicKeyPEM(successorPublicKey), status: "active", supersedes_kid: "release-a" },
  ] };
  const successorHash = await registryDigest(successor);
  const oldKeyClaims: SignatureClaims = { ...claims, key_registry_id: successor.registry_id, key_registry_hash: successorHash };
  const oldKeyClaimsBytes = new TextEncoder().encode(canonicalizeJson(oldKeyClaims as unknown as JsonValue));
  const oldKeySignature = new Uint8Array(await crypto.subtle.sign({ name: "RSA-PSS", saltLength: 32 }, keys.privateKey, oldKeyClaimsBytes));
  const oldKeyEnvelope = { ...oldKeyClaims, envelope_id: await typedDigest("signature_envelope", "1.0.0", oldKeyClaims as unknown as JsonValue), signature_base64: base64(oldKeySignature) };
  const successorExpected = { ...expected, registryHash: successorHash, at: new Date("2026-07-18T02:00:00Z") };
  assert.equal(await verifyDetached(payload, oldKeyEnvelope, successor, successorExpected), false);
  const newKeyClaims: SignatureClaims = { ...oldKeyClaims, kid: "release-b" };
  const newKeyClaimsBytes = new TextEncoder().encode(canonicalizeJson(newKeyClaims as unknown as JsonValue));
  const newKeySignature = new Uint8Array(await crypto.subtle.sign({ name: "RSA-PSS", saltLength: 32 }, successorKeys.privateKey, newKeyClaimsBytes));
  const newKeyEnvelope = { ...newKeyClaims, envelope_id: await typedDigest("signature_envelope", "1.0.0", newKeyClaims as unknown as JsonValue), signature_base64: base64(newKeySignature) };
  assert.equal(await verifyDetached(payload, newKeyEnvelope, successor, successorExpected), true);
  assert.equal(newKeyEnvelope.payload_digest, identityBefore);
});
